function timer(fn) {
  return function(...args) {
    const start = Date.now();
    const result = fn(...args);
    console.log(`${fn.name} took ${Date.now() - start}ms`);
    return result;
  };
}

const slowFunction = timer(() => {
  const start = Date.now();
  while(Date.now() - start < 1000);
  return "Done";
});

slowFunction();
